-- ========================================
-- VALIDATION SCRIPT FOR cancel_rebuy.sql
-- JIRA: HAT-3923
-- Generated: 2026-03-11
-- ========================================

-- ========================================
-- 1. ROW COUNT CHECKS
-- ========================================

-- 1.1 Source table row count
SELECT 'Source Table: renewal_360' AS check_name, 
       COUNT(*) AS row_count,
       'Expected: > 0' AS expected_result
FROM dev.dna_approved.renewal_360;

-- 1.2 Target table row count
SELECT 'Target Table: cancel_rebuy' AS check_name,
       COUNT(*) AS row_count,
       'Expected: > 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy;

-- 1.3 CTE 1 (cancelled entitlements) row count
SELECT 'CTE 1: Cancelled Entitlements' AS check_name,
       COUNT(DISTINCT resource_id) AS distinct_resources,
       COUNT(*) AS total_rows,
       'Expected: distinct_resources = total_rows' AS expected_result
FROM dev.dna_approved.renewal_360
WHERE entitlement_cancel_mst_date IS NOT NULL 
  AND bill_exclude_reason_desc IS NULL
  AND LOWER(prior_bill_product_pnl_group_name) <> 'domains'
  AND prior_bill_primary_product_flag = TRUE
  AND entitlement_cancel_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 60;

-- 1.4 CTE 2 (new orders) row count
SELECT 'CTE 2: New Orders' AS check_name,
       COUNT(DISTINCT resource_id) AS distinct_resources,
       COUNT(*) AS total_rows,
       'Expected: distinct_resources = total_rows' AS expected_result
FROM dev.dna_approved.renewal_360
WHERE prior_bill_modified_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 1
  AND bill_exclude_reason_desc IS NULL 
  AND prior_bill_product_pnl_new_renewal_name = 'New Purchase' 
  AND prior_bill_sequence_number = 1
  AND prior_bill_primary_product_flag = TRUE
  AND LOWER(prior_bill_product_pnl_group_name) <> 'domains';

-- ========================================
-- 2. NULL VALUE CHECKS FOR CRITICAL COLUMNS
-- ========================================

-- 2.1 Check for nulls in target table primary identifiers
SELECT 'NULL Check: resource_id' AS check_name,
       COUNT(*) AS null_count,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE resource_id IS NULL;

SELECT 'NULL Check: prior_bill_shopper_id' AS check_name,
       COUNT(*) AS null_count,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE prior_bill_shopper_id IS NULL;

SELECT 'NULL Check: product_family_name' AS check_name,
       COUNT(*) AS null_count,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE product_family_name IS NULL;

SELECT 'NULL Check: entitlement_cancel_mst_date' AS check_name,
       COUNT(*) AS null_count,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE entitlement_cancel_mst_date IS NULL;

-- 2.2 Check for nulls in flag columns (should never be null due to COALESCE logic)
SELECT 'NULL Check: All Flags' AS check_name,
       SUM(CASE WHEN cancel_rebuy_flag IS NULL THEN 1 ELSE 0 END) AS cancel_rebuy_flag_nulls,
       SUM(CASE WHEN cancel_rebuy_product_pnl_group_flag IS NULL THEN 1 ELSE 0 END) AS group_flag_nulls,
       SUM(CASE WHEN cancel_rebuy_product_pnl_category_flag IS NULL THEN 1 ELSE 0 END) AS category_flag_nulls,
       SUM(CASE WHEN cancel_rebuy_product_pnl_line_flag IS NULL THEN 1 ELSE 0 END) AS line_flag_nulls,
       SUM(CASE WHEN cancel_rebuy_product_pnl_version_flag IS NULL THEN 1 ELSE 0 END) AS version_flag_nulls,
       'Expected: All 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy;

-- ========================================
-- 3. DUPLICATE DETECTION
-- ========================================

-- 3.1 Check for duplicate resource_ids in target table
SELECT 'Duplicate Check: resource_id' AS check_name,
       resource_id,
       COUNT(*) AS occurrence_count,
       'Expected: occurrence_count = 1 for all rows' AS expected_result
FROM ba_ecommerce.cancel_rebuy
GROUP BY resource_id
HAVING COUNT(*) > 1;

-- 3.2 Check for duplicate composite keys (resource_id + shopper_id + product_family + cancel_date)
SELECT 'Duplicate Check: Composite Key' AS check_name,
       resource_id,
       prior_bill_shopper_id,
       product_family_name,
       entitlement_cancel_mst_date,
       COUNT(*) AS occurrence_count,
       'Expected: occurrence_count = 1 for all rows' AS expected_result
FROM ba_ecommerce.cancel_rebuy
GROUP BY resource_id, prior_bill_shopper_id, product_family_name, entitlement_cancel_mst_date
HAVING COUNT(*) > 1;

-- 3.3 Check for duplicate resource_ids in source CTE 1
SELECT 'Duplicate Check: CTE 1 resource_id' AS check_name,
       resource_id,
       COUNT(*) AS occurrence_count,
       'Expected: occurrence_count = 1 for all rows' AS expected_result
FROM dev.dna_approved.renewal_360
WHERE entitlement_cancel_mst_date IS NOT NULL 
  AND bill_exclude_reason_desc IS NULL
  AND LOWER(prior_bill_product_pnl_group_name) <> 'domains'
  AND prior_bill_primary_product_flag = TRUE
  AND entitlement_cancel_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 60
GROUP BY resource_id
HAVING COUNT(*) > 1;

-- ========================================
-- 4. JOIN VALIDATION
-- ========================================

-- 4.1 Verify all records from CTE 1 exist in target table
SELECT 'Join Validation: CTE 1 to Target' AS check_name,
       COUNT(*) AS orphaned_records,
       'Expected: 0' AS expected_result
FROM (
  SELECT DISTINCT resource_id
  FROM dev.dna_approved.renewal_360
  WHERE entitlement_cancel_mst_date IS NOT NULL 
    AND bill_exclude_reason_desc IS NULL
    AND LOWER(prior_bill_product_pnl_group_name) <> 'domains'
    AND prior_bill_primary_product_flag = TRUE
    AND entitlement_cancel_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 60
) cte1
LEFT JOIN ba_ecommerce.cancel_rebuy cr
  ON cte1.resource_id = cr.resource_id
WHERE cr.resource_id IS NULL;

-- 4.2 Verify no unexpected records in target table (all should come from CTE 1)
SELECT 'Join Validation: Target to CTE 1' AS check_name,
       COUNT(*) AS unexpected_records,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy cr
LEFT JOIN (
  SELECT DISTINCT resource_id
  FROM dev.dna_approved.renewal_360
  WHERE entitlement_cancel_mst_date IS NOT NULL 
    AND bill_exclude_reason_desc IS NULL
    AND LOWER(prior_bill_product_pnl_group_name) <> 'domains'
    AND prior_bill_primary_product_flag = TRUE
    AND entitlement_cancel_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 60
) cte1
  ON cr.resource_id = cte1.resource_id
WHERE cte1.resource_id IS NULL;

-- 4.3 Validate join logic - shoppers with cancel_rebuy_flag=1 should exist in CTE 2
SELECT 'Join Validation: Rebuy Flag Logic' AS check_name,
       COUNT(*) AS mismatched_records,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy cr
WHERE cr.cancel_rebuy_flag = 1
  AND NOT EXISTS (
    SELECT 1
    FROM dev.dna_approved.renewal_360 r
    WHERE r.prior_bill_shopper_id = cr.prior_bill_shopper_id
      AND r.product_family_name = cr.product_family_name
      AND r.prior_bill_modified_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 1
      AND r.bill_exclude_reason_desc IS NULL 
      AND r.prior_bill_product_pnl_new_renewal_name = 'New Purchase' 
      AND r.prior_bill_sequence_number = 1
      AND r.prior_bill_primary_product_flag = TRUE
      AND LOWER(r.prior_bill_product_pnl_group_name) <> 'domains'
      AND r.prior_bill_modified_mst_date BETWEEN DATEADD(DAY, 30, cr.entitlement_cancel_mst_date)
        AND DATEADD(DAY, 60, cr.entitlement_cancel_mst_date)
  );

-- ========================================
-- 5. BUSINESS RULE VALIDATION
-- ========================================

-- 5.1 Validate date range for entitlement_cancel_mst_date
SELECT 'Business Rule: Cancel Date Range' AS check_name,
       MIN(entitlement_cancel_mst_date) AS min_cancel_date,
       MAX(entitlement_cancel_mst_date) AS max_cancel_date,
       'Expected: min >= 2024-01-01, max <= CURRENT_DATE - 60' AS expected_result
FROM ba_ecommerce.cancel_rebuy;

SELECT 'Business Rule: Cancel Date Out of Range' AS check_name,
       COUNT(*) AS out_of_range_count,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE entitlement_cancel_mst_date < '2024-01-01' 
   OR entitlement_cancel_mst_date > CURRENT_DATE - 60;

-- 5.2 Validate flag values are binary (0 or 1)
SELECT 'Business Rule: Flag Values' AS check_name,
       SUM(CASE WHEN cancel_rebuy_flag NOT IN (0, 1) THEN 1 ELSE 0 END) AS invalid_cancel_rebuy_flag,
       SUM(CASE WHEN cancel_rebuy_product_pnl_group_flag NOT IN (0, 1) THEN 1 ELSE 0 END) AS invalid_group_flag,
       SUM(CASE WHEN cancel_rebuy_product_pnl_category_flag NOT IN (0, 1) THEN 1 ELSE 0 END) AS invalid_category_flag,
       SUM(CASE WHEN cancel_rebuy_product_pnl_line_flag NOT IN (0, 1) THEN 1 ELSE 0 END) AS invalid_line_flag,
       SUM(CASE WHEN cancel_rebuy_product_pnl_version_flag NOT IN (0, 1) THEN 1 ELSE 0 END) AS invalid_version_flag,
       'Expected: All 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy;

-- 5.3 Validate flag hierarchy logic (more specific flags <= general flags)
SELECT 'Business Rule: Flag Hierarchy' AS check_name,
       COUNT(*) AS hierarchy_violations,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE cancel_rebuy_product_pnl_group_flag > cancel_rebuy_flag
   OR cancel_rebuy_product_pnl_category_flag > cancel_rebuy_flag
   OR cancel_rebuy_product_pnl_line_flag > cancel_rebuy_flag
   OR cancel_rebuy_product_pnl_version_flag > cancel_rebuy_flag;

-- 5.4 Validate primary_product_flag filter was applied
SELECT 'Business Rule: Primary Product Filter' AS check_name,
       COUNT(*) AS non_primary_products,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy cr
INNER JOIN dev.dna_approved.renewal_360 r
  ON cr.resource_id = r.resource_id
WHERE r.prior_bill_primary_product_flag = FALSE;

-- 5.5 Validate domains exclusion
SELECT 'Business Rule: Domains Exclusion' AS check_name,
       COUNT(*) AS domain_records,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy cr
INNER JOIN dev.dna_approved.renewal_360 r
  ON cr.resource_id = r.resource_id
WHERE LOWER(r.prior_bill_product_pnl_group_name) = 'domains';

-- 5.6 Validate bill_exclude_reason_desc is null
SELECT 'Business Rule: Bill Exclude Reason' AS check_name,
       COUNT(*) AS excluded_records,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy cr
INNER JOIN dev.dna_approved.renewal_360 r
  ON cr.resource_id = r.resource_id
WHERE r.bill_exclude_reason_desc IS NOT NULL;

-- ========================================
-- 6. DATA TYPE VALIDATION
-- ========================================

-- 6.1 Verify data types of key columns
SELECT 'Data Type Check: Column Info' AS check_name,
       column_name,
       data_type,
       'Expected: Appropriate types' AS expected_result
FROM information_schema.columns
WHERE table_schema = 'ba_ecommerce'
  AND table_name = 'cancel_rebuy'
ORDER BY ordinal_position;

-- 6.2 Check for numeric column ranges
SELECT 'Data Type: Flag Column Ranges' AS check_name,
       MIN(cancel_rebuy_flag) AS min_cancel_rebuy_flag,
       MAX(cancel_rebuy_flag) AS max_cancel_rebuy_flag,
       MIN(cancel_rebuy_product_pnl_group_flag) AS min_group_flag,
       MAX(cancel_rebuy_product_pnl_group_flag) AS max_group_flag,
       'Expected: All min=0, max=1' AS expected_result
FROM ba_ecommerce.cancel_rebuy;

-- ========================================
-- 7. AGGREGATE METRIC VERIFICATION
-- ========================================

-- 7.1 Overall rebuy rate
SELECT 'Metric: Overall Rebuy Rate' AS metric_name,
       COUNT(*) AS total_cancellations,
       SUM(cancel_rebuy_flag) AS total_rebuys,
       ROUND(SUM(cancel_rebuy_flag) * 100.0 / COUNT(*), 2) AS rebuy_rate_pct,
       'Expected: 0 <= rebuy_rate_pct <= 100' AS expected_result
FROM ba_ecommerce.cancel_rebuy;

-- 7.2 Rebuy rates by product hierarchy
SELECT 'Metric: Rebuy Rates by Hierarchy' AS metric_name,
       ROUND(SUM(cancel_rebuy_flag) * 100.0 / COUNT(*), 2) AS overall_rebuy_rate,
       ROUND(SUM(cancel_rebuy_product_pnl_group_flag) * 100.0 / NULLIF(SUM(cancel_rebuy_flag), 0), 2) AS same_group_rate,
       ROUND(SUM(cancel_rebuy_product_pnl_category_flag) * 100.0 / NULLIF(SUM(cancel_rebuy_flag), 0), 2) AS same_category_rate,
       ROUND(SUM(cancel_rebuy_product_pnl_line_flag) * 100.0 / NULLIF(SUM(cancel_rebuy_flag), 0), 2) AS same_line_rate,
       ROUND(SUM(cancel_rebuy_product_pnl_version_flag) * 100.0 / NULLIF(SUM(cancel_rebuy_flag), 0), 2) AS same_version_rate,
       'Expected: Rates decrease from group to version' AS expected_result
FROM ba_ecommerce.cancel_rebuy;

-- 7.3 Distribution by product family
SELECT 'Metric: Top 10 Product Families by Cancellation' AS metric_name,
       product_family_name,
       COUNT(*) AS cancellation_count,
       SUM(cancel_rebuy_flag) AS rebuy_count,
       ROUND(SUM(cancel_rebuy_flag) * 100.0 / COUNT(*), 2) AS rebuy_rate_pct
FROM ba_ecommerce.cancel_rebuy
GROUP BY product_family_name
ORDER BY cancellation_count DESC
LIMIT 10;

-- 7.4 Monthly trend of cancellations and rebuys
SELECT 'Metric: Monthly Cancellation & Rebuy Trend' AS metric_name,
       DATE_TRUNC('month', entitlement_cancel_mst_date) AS cancel_month,
       COUNT(*) AS cancellation_count,
       SUM(cancel_rebuy_flag) AS rebuy_count,
       ROUND(SUM(cancel_rebuy_flag) * 100.0 / COUNT(*), 2) AS rebuy_rate_pct
FROM ba_ecommerce.cancel_rebuy
GROUP BY DATE_TRUNC('month', entitlement_cancel_mst_date)
ORDER BY cancel_month;

-- 7.5 Unique shopper counts
SELECT 'Metric: Unique Shoppers' AS metric_name,
       COUNT(DISTINCT prior_bill_shopper_id) AS unique_shoppers,
       COUNT(*) AS total_cancellations,
       ROUND(COUNT(*) * 1.0 / COUNT(DISTINCT prior_bill_shopper_id), 2) AS avg_cancels_per_shopper,
       'Expected: avg_cancels_per_shopper >= 1.0' AS expected_result
FROM ba_ecommerce.cancel_rebuy;

-- 7.6 Rebuy window validation (30-60 days after cancellation)
SELECT 'Metric: Rebuy Window Distribution' AS metric_name,
       COUNT(*) AS rebuys_in_window,
       'Expected: All rebuys should be in 30-60 day window' AS expected_result
FROM ba_ecommerce.cancel_rebuy cr
WHERE cr.cancel_rebuy_flag = 1;

-- 7.7 Compare CTE totals to target table
SELECT 'Metric: Record Reconciliation' AS metric_name,
       (SELECT COUNT(DISTINCT resource_id) FROM dev.dna_approved.renewal_360
        WHERE entitlement_cancel_mst_date IS NOT NULL 
          AND bill_exclude_reason_desc IS NULL
          AND LOWER(prior_bill_product_pnl_group_name) <> 'domains'
          AND prior_bill_primary_product_flag = TRUE
          AND entitlement_cancel_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 60) AS cte1_count,
       (SELECT COUNT(*) FROM ba_ecommerce.cancel_rebuy) AS target_table_count,
       'Expected: cte1_count = target_table_count' AS expected_result;

-- ========================================
-- 8. EDGE CASE VALIDATION
-- ========================================

-- 8.1 Check for shoppers with multiple cancellations
SELECT 'Edge Case: Multiple Cancellations per Shopper' AS check_name,
       prior_bill_shopper_id,
       COUNT(*) AS cancellation_count,
       'Expected: Varies (some shoppers may cancel multiple products)' AS expected_result
FROM ba_ecommerce.cancel_rebuy
GROUP BY prior_bill_shopper_id
HAVING COUNT(*) > 1
ORDER BY cancellation_count DESC
LIMIT 20;

-- 8.2 Check for records near date boundaries
SELECT 'Edge Case: Records Near Date Boundaries' AS check_name,
       COUNT(CASE WHEN entitlement_cancel_mst_date = '2024-01-01' THEN 1 END) AS first_day_count,
       COUNT(CASE WHEN entitlement_cancel_mst_date = CURRENT_DATE - 60 THEN 1 END) AS last_day_count,
       'Expected: Counts should be reasonable' AS expected_result
FROM ba_ecommerce.cancel_rebuy;

-- 8.3 Validate no future dates
SELECT 'Edge Case: Future Dates' AS check_name,
       COUNT(*) AS future_date_count,
       'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE entitlement_cancel_mst_date > CURRENT_DATE;

-- ========================================
-- END OF VALIDATION SCRIPT
-- ========================================
